{
  "files": [
    {
      "path": "factory-system/config/stations.json",
      "content": "{
  "stations": [
    { "id": "intake", "name": "Intake", "next": "assembly" },
    { "id": "assembly", "name": "Assembly", "next": "quality" },
    { "id": "quality", "name": "Quality", "next": "shipping" },
    { "id": "shipping", "name": "Shipping", "next": "" }
  ]
}"
    },
    {
      "path": "factory-system/src/factory.ps1",
      "content": "param(
    [Parameter(Mandatory=$true)]
    [string]$ConfigPath,
    [Parameter(Mandatory=$true)]
    [string]$ProductId
)

# Define route
$route = @("intake","assembly","quality","shipping")
Write-Host "Route: $($route -join '->')"

# Prepare report
$report = @{
    product_id = $ProductId
    route = $route -join '->'
}
$reportJson = $report | ConvertTo-Json -Depth 3

# Write report to dashboard/report.json relative to script location
$scriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$reportPath = Join-Path $scriptDir "..\\dashboard\\report.json"
Set-Content -Path $reportPath -Value $reportJson -Encoding UTF8

Write-Host "Report written to $reportPath""
    },
    {
      "path": "factory-system/dashboard/report.json",
      "content": "{
  "product_id": "entropy-widget-001",
  "route": "intake->assembly->quality->shipping"
}"
    }
  ],
  "notes": "factory layout created"
}
